; EarthBound C1 Battle item selection loop.
;
; Source-emission status:
; - Prototype level: build-candidate
; - Generated by tools/emit_linear_source_module.py from a state-aware
;   linear ROM decode, then intended for byte-equivalence validation.
;
; Source units covered:
; - C1:CFC6..C1:D038 OpenBattleItemSelectionLoop

; ---------------------------------------------------------------------------
; External contracts used by this module
; - Input A points to the same battle item-selection record consumed by
;   C1:CE85: byte +0 is actor/character id and byte +1 receives the chosen
;   inventory slot.
; - The first inventory slot at $99F1 + actor party-record offset is the
;   fast empty-inventory gate.
; - Nonempty inventories render through C1:98DE, run the generic menu loop at
;   C1:196A, then call C1:CE85 to turn the selected slot into action/target
;   state.

C10084_CloseFocusWindow                        = $0084
C104EE_SetWindowFocus                          = $04EE
C1196A_OpenMenuSelectionLoop                   = $196A
C198DE_RenderCharacterInventoryOrEquipmentRows = $98DE
C1CE85_ResolveSelectedBattleItemAction         = $CE85
C08FF7_ResolveIndexedPointerOffset             = $C08FF7
C3E4D4_EnterWindowUpdateScope                  = $C3E4D4
C3E521_CloseWindowAndReleaseTileState          = $C3E521

BattleItemSelectionActorId      = $0000
BattleItemSelectionSelectedSlot = $0001
PartyRecordStride               = $005F
PartyRecordFirstInventoryItem   = $99F1

; ---------------------------------------------------------------------------
; C1:CFC6

C1CFC6_OpenBattleItemSelectionLoop:
    rep #$31
    phd
    pha
    tdc
    adc.w #$FFEE
    tcd
    pla
    tay
    sty $10
    ldx.w #$0000
    stx $0E
    lda BattleItemSelectionActorId,Y
    and.w #$00FF
    dec A
    ldy.w #PartyRecordStride
    jsl C08FF7_ResolveIndexedPointerOffset
    tax
    ; Empty inventory: first item slot is zero, so the battle item command
    ; returns 0 without opening the menu.
    lda PartyRecordFirstInventoryItem,X
    and.w #$00FF
    beq C1D033_OpenBattleItemSelectionLoop_LD033
C1CFEF_OpenBattleItemSelectionLoop_LCFEF:
    lda.w #$0002
    jsr C104EE_SetWindowFocus
    ldx.w #$0002
    ldy $10
    lda BattleItemSelectionActorId,Y
    and.w #$00FF
    jsr INVENTORY_GET_ITEM_NAME
    lda.w #$0001
    jsr C1196A_OpenMenuSelectionLoop
    tax
    stx $0E
    jsl C3E4D4_EnterWindowUpdateScope
    jsr CLOSE_FOCUS_WINDOW
    ldx $0E
    beq C1D033_OpenBattleItemSelectionLoop_LD033
    txa
    sep #$20
    ldy $10
    sta BattleItemSelectionSelectedSlot,Y
    rep #$20
    tya
    jsr C1CE85_ResolveSelectedBattleItemAction
    tax
    stx $0E
    lda.w #$0026
    jsl C3E521_CloseWindowAndReleaseTileState
    ldx $0E
    ; A zero result from C1:CE85 means the chosen item was rejected after
    ; target/usability resolution, so reopen the item list.
    beq C1CFEF_OpenBattleItemSelectionLoop_LCFEF
C1D033_OpenBattleItemSelectionLoop_LD033:
    ldx $0E
    txa
    pld
    rts
